Implementing a `Dictionary` type in C is super exciting! While C doesn't have built-in dictionaries like some other languages, you can create one using structures and arrays or even linked lists for more complex scenarios. Here’s a simple example using an array-based approach:

```c
#include <stdio.h>
#include <stdlib.h>

#define MAX_SIZE 100

typedef struct {
    char *key;
    int value;
} KeyValuePair;

typedef struct {
    KeyValuePair pairs[MAX_SIZE];
    int count;
} SimpleDictionary;

void addKeyValuePair(SimpleDictionary *dict, const char *key, int value) {
    if (dict->count >= MAX_SIZE) {
        printf("Dictionary is full!\n");
        return;
    }
    dict->pairs[dict->count].key = strdup(key);
    dict->pairs[dict->count].value = value;
    dict->count++;
}

int getValueFromKey(SimpleDictionary *dict, const char *key) {
    for (int i = 0; i < dict->count; i++) {
        if (strcmp(dict->pairs[i].key, key) == 0) {
            return dict->pairs[i].value;
        }
    }
    return -1; // Key not found
}

int main() {
    SimpleDictionary dict = {0};
    addKeyValuePair(&dict, "apple", 5);
    addKeyValuePair(&dict, "banana", 3);

    printf("Value of 'apple': %d\n", getValueFromKey(&dict, "apple"));
    printf("Value of 'banana': %d\n", getValueFromKey(&dict, "banana"));

    return 0;
}
```

